class Solution {
public:
    bool canMeasureWater(int x, int y, int target) {
        if (target == 0) return true;
        if (x == 0 && y == 0) return target == 0;
        int gcd = getGCD(x, y);
        return target % gcd == 0 && target <= x + y;
    }

    int getGCD(int a, int b) {
        if (b == 0) return a;
        return getGCD(b, a % b);
    }
};
```
